//! Dialect tests for the in-memory test backend.
//!
//! These pin the test backend's SQL output directly, rather than relying on the
//! incidental assertions in `squealy`'s `derive_metadata.rs`. The notable
//! differences from the PostgreSQL backend are the `?` bind placeholders (vs
//! `$1`, `$2`) and the `AUTOINCREMENT` DDL keyword (vs
//! `GENERATED BY DEFAULT AS IDENTITY`).

use squealy::*;
use squealy_test::{TestBackend, TestConnection, TestParam};

#[derive(Clone, Debug, PartialEq, Table)]
#[schema(Public)]
struct User<'scope, C: ColumnMode = ColumnExpr> {
    #[column(primary_key, auto_increment)]
    id: C::Type<'scope, i32>,
    name: C::Type<'scope, String>,
}

#[derive(Clone, Debug, PartialEq, Table)]
struct DefaultedRecord<'scope, C: ColumnMode = ColumnExpr> {
    #[column(primary_key, auto_increment)]
    id: C::Type<'scope, i32>,
}

#[derive(Clone, Debug, PartialEq, Table)]
struct Counter<'scope, C: ColumnMode = ColumnExpr> {
    #[column(primary_key, auto_increment)]
    id: C::Type<'scope, i32>,
    count: C::Type<'scope, i32>,
}

#[allow(dead_code)]
#[derive(Schema)]
struct Public {
    users: User<'static, ColumnName>,
}

#[test]
fn test_select_uses_question_mark_placeholders() {
    let users = TestConnection
        .from::<User>()
        .where_(|user| user.id.equals(1))
        .select(|(user,)| user.id + 2);

    assert_eq!(
        users.to_sql(),
        "SELECT (q0_0.id + ?) AS expr FROM public.users AS q0_0 WHERE (q0_0.id = ?)"
    );
    let mut written = Vec::new();
    users.write_params(&mut written).unwrap();
    assert_eq!(written, vec![TestParam::Int(2), TestParam::Int(1)]);
    assert_eq!(
        users.collect_params().unwrap(),
        vec![TestParam::Int(2), TestParam::Int(1)]
    );
}

#[test]
fn test_runtime_prepared_params_render_without_captured_values() {
    let users = TestConnection
        .from::<User>()
        .where_(|user| user.name.equals(param::<UserName>()))
        .select(|(user,)| user.name);

    assert_eq!(
        users.to_sql(),
        "SELECT q0_0.name AS name FROM public.users AS q0_0 WHERE (q0_0.name = ?)"
    );
    assert_eq!(users.collect_params().unwrap(), Vec::<TestParam>::new());
}

#[test]
fn test_runtime_prepared_assignment_params_render_without_captured_values() {
    let insert = TestConnection
        .to::<User>()
        .name(param::<UserName>())
        .insert_returning(|user| user.id);
    let update = TestConnection
        .to::<User>()
        .name(param::<UserName>())
        .where_(|user| user.id.equals(param::<UserId>()))
        .update_returning(|user| user.name);

    assert_eq!(
        insert.to_sql(),
        "INSERT INTO public.users (name) VALUES (?) RETURNING q0_0.id AS id"
    );
    assert_eq!(
        update.to_sql(),
        "UPDATE public.users AS q0_0 SET name = ? WHERE (q0_0.id = ?) RETURNING q0_0.name AS name"
    );
    assert_eq!(insert.collect_params().unwrap(), Vec::<TestParam>::new());
    assert_eq!(update.collect_params().unwrap(), Vec::<TestParam>::new());
}

#[test]
fn test_update_renders_explicit_defaults() {
    let update = TestConnection
        .to::<User>()
        .name(default())
        .where_(|user| user.id.equals(1))
        .update_returning(|user| user.name);

    assert_eq!(
        update.to_sql(),
        "UPDATE public.users AS q0_0 SET name = DEFAULT WHERE (q0_0.id = ?) RETURNING q0_0.name AS name"
    );
    assert_eq!(update.collect_params().unwrap(), vec![TestParam::Int(1)]);
}

#[test]
fn test_explicit_update_columns_render_expression_assignments() {
    let update = TestConnection
        .to_columns::<Counter, (CounterCount,)>()
        .set(|counter| (counter.count + 1,))
        .where_(|counter| counter.id.equals(7))
        .update_returning(|counter| counter.count);

    assert_eq!(
        update.to_sql(),
        "UPDATE counters AS q0_0 SET count = (q0_0.count + ?) WHERE (q0_0.id = ?) RETURNING q0_0.count AS count"
    );
    assert_eq!(
        update.collect_params().unwrap(),
        vec![TestParam::Int(1), TestParam::Int(7)]
    );
}

#[test]
fn test_insert_update_and_delete_render_returning() {
    let insert = TestConnection
        .to::<User>()
        .name("Ada")
        .insert_returning(|user| user.id);
    let update = TestConnection
        .to::<User>()
        .name("Ada")
        .where_(|user| user.id.equals(1))
        .update_returning(|user| (user.id, user.name));
    let delete = TestConnection
        .from::<User>()
        .where_(|user| user.id.equals(1))
        .delete_returning(|user| user);

    assert_eq!(
        insert.to_sql(),
        "INSERT INTO public.users (name) VALUES (?) RETURNING q0_0.id AS id"
    );
    assert_eq!(
        update.to_sql(),
        "UPDATE public.users AS q0_0 SET name = ? WHERE (q0_0.id = ?) RETURNING q0_0.id AS t0_id, q0_0.name AS t1_name"
    );
    assert_eq!(
        delete.to_sql(),
        "DELETE FROM public.users AS q0_0 WHERE (q0_0.id = ?) RETURNING q0_0.id AS id, q0_0.name AS name"
    );
    assert_eq!(
        insert.collect_params().unwrap(),
        vec![TestParam::Text("Ada".to_owned())]
    );
    assert_eq!(
        update.collect_params().unwrap(),
        vec![TestParam::Text("Ada".to_owned()), TestParam::Int(1)]
    );
    assert_eq!(delete.collect_params().unwrap(), vec![TestParam::Int(1)]);
}

#[test]
fn test_insert_renders_multiple_rows() {
    let insert = TestConnection
        .to_columns::<User, (UserName,)>()
        .row(("Ada",))
        .row(("Grace",))
        .insert_returning(|user| user.id);

    assert_eq!(
        insert.to_sql(),
        "INSERT INTO public.users (name) VALUES (?), (?) RETURNING q0_0.id AS id"
    );
    assert_eq!(
        insert.collect_params().unwrap(),
        vec![
            TestParam::Text("Ada".to_owned()),
            TestParam::Text("Grace".to_owned())
        ]
    );
}

#[test]
fn test_insert_renders_explicit_defaults() {
    let insert = TestConnection
        .to_columns::<User, (UserName,)>()
        .row((default(),))
        .row(("Grace",))
        .insert_returning(|user| user.id);

    assert_eq!(
        insert.to_sql(),
        "INSERT INTO public.users (name) VALUES (DEFAULT), (?) RETURNING q0_0.id AS id"
    );
    assert_eq!(
        insert.collect_params().unwrap(),
        vec![TestParam::Text("Grace".to_owned())]
    );
}

#[test]
fn test_insert_can_use_default_values() {
    let insert = TestConnection
        .to::<DefaultedRecord>()
        .insert_returning(|record| record.id);

    assert_eq!(
        insert.to_sql(),
        "INSERT INTO defaulted_records DEFAULT VALUES RETURNING q0_0.id AS id"
    );
    assert_eq!(insert.collect_params().unwrap(), Vec::<TestParam>::new());
}

#[test]
fn test_queries_can_be_prepared() {
    {
        let select = TestConnection
            .from::<User>()
            .where_(|user| user.id.equals(1))
            .select(|(user,)| user.name);
        let _prepare = select.prepare();
    }

    {
        let insert = TestConnection
            .to::<User>()
            .name("Ada")
            .insert_returning(|user| user.id);
        let _prepare = insert.prepare();
    }

    {
        let update = TestConnection
            .to::<User>()
            .name("Ada")
            .where_(|user| user.id.equals(1))
            .update_returning(|user| user.id);
        let _prepare = update.prepare();
    }

    {
        let delete = TestConnection
            .from::<User>()
            .where_(|user| user.id.equals(1))
            .delete_returning(|user| user.id);
        let _prepare = delete.prepare();
    }
}

#[test]
fn test_runtime_param_queries_can_be_prepared() {
    {
        let select = TestConnection
            .from::<User>()
            .where_(|user| user.name.equals(param::<UserName>()))
            .select(|(user,)| user.id);
        let _prepare = select.prepare();
    }

    {
        let insert = TestConnection
            .to::<User>()
            .name(param::<UserName>())
            .insert_returning(|user| user.id);
        let _prepare = insert.prepare();
    }

    {
        let insert = TestConnection
            .to_columns::<User, (UserName,)>()
            .row((param::<UserName>(),))
            .row((param::<UserName>(),))
            .insert_returning(|user| user.id);
        let _prepare = insert.prepare();
    }

    {
        let update = TestConnection
            .to::<User>()
            .name(param::<UserName>())
            .where_(|user| user.id.equals(param::<UserId>()))
            .update_returning(|user| user.id);
        let _prepare = update.prepare();
    }

    {
        let delete = TestConnection
            .from::<User>()
            .where_(|user| user.id.equals(param::<UserId>()))
            .delete_returning(|user| user.id);
        let _prepare = delete.prepare();
    }
}

#[test]
fn test_backend_writes_table_ddl_with_autoincrement() {
    let mut sql = Vec::new();
    let tables = <Public as Schema>::tables().collect::<Vec<_>>();
    TestBackend.write_table(tables[0], &mut sql).unwrap();
    let sql = String::from_utf8(sql).unwrap();

    assert_eq!(
        sql,
        "CREATE TABLE public.users (id integer PRIMARY KEY AUTOINCREMENT NOT NULL, name text NOT NULL)"
    );
}

#[derive(Clone, Debug, PartialEq, Table)]
#[schema(Public)]
#[primary_key(columns = [tenant_id, id])]
struct Seat<'scope, C: ColumnMode = ColumnExpr> {
    tenant_id: C::Type<'scope, i32>,
    id: C::Type<'scope, i32>,
}

#[allow(dead_code)]
#[derive(Schema)]
struct SeatPublic {
    seats: Seat<'static, ColumnName>,
}

#[test]
fn test_backend_writes_compound_primary_key_ddl() {
    // The query-side single-table `write_table` path must also honor a table-level primary key.
    let mut sql = Vec::new();
    let tables = <SeatPublic as Schema>::tables().collect::<Vec<_>>();
    TestBackend.write_table(tables[0], &mut sql).unwrap();
    let sql = String::from_utf8(sql).unwrap();

    assert_eq!(
        sql,
        "CREATE TABLE public.seats (tenant_id integer NOT NULL, id integer NOT NULL, PRIMARY KEY (tenant_id, id))"
    );
}

#[derive(Clone, Debug, PartialEq, Table)]
#[schema(Public)]
struct Account<'scope, C: ColumnMode = ColumnExpr> {
    #[column(primary_key, auto_increment)]
    id: C::Type<'scope, i32>,
    #[column(nullable)]
    nickname: C::Type<'scope, String>,
}

#[test]
fn test_is_null_renders_is_null() {
    let accounts = TestConnection
        .from::<Account>()
        .where_(|account| account.nickname.is_null())
        .select(|(account,)| account.id);

    assert_eq!(
        accounts.to_sql(),
        "SELECT q0_0.id AS id FROM public.accounts AS q0_0 WHERE (q0_0.nickname IS NULL)"
    );
    assert_eq!(accounts.collect_params().unwrap(), Vec::<TestParam>::new());
}

#[test]
fn test_is_not_null_composes_with_other_predicates() {
    let accounts = TestConnection
        .from::<Account>()
        .where_(|account| account.nickname.is_not_null().or(account.id.equals(1)))
        .select(|(account,)| account.id);

    assert_eq!(
        accounts.to_sql(),
        "SELECT q0_0.id AS id FROM public.accounts AS q0_0 WHERE ((q0_0.nickname IS NOT NULL) OR (q0_0.id = ?))"
    );
    assert_eq!(accounts.collect_params().unwrap(), vec![TestParam::Int(1)]);
}
